+			Reseq: reseq.Stats{Released: 51},
+		},
+		{
+			Name:  "edge2",
+			Paths: []bind.PathTraffic{{Name: "starlink", TxBytes: 6000, RxBytes: 0}}, // +1000 bytes
+			FEC:   bind.FECStats{DataFrames: 705, ParityFrames: 141},
+			Reseq: reseq.Stats{Released: 950},
