+		t.Fatalf("Reseq len = %d, want 2", len(reseqSnaps))
+	}
+	reseqByPeer := map[string]metrics.ReseqSnapshot{}
+	for _, r := range reseqSnaps {
+		reseqByPeer[r.Peer] = r
+	}
+	if got, want := reseqByPeer[""].Released, uint64(51); got != want {
